// Formate les alertes ES pour Teams
const hits = $input.item.json.hits.hits;
const alerts = hits.map(hit => {
  const src = hit._source;
  const ts = src['@timestamp'] || 'N/A';
  const srcIp = src.src_ip || src['source.ip'] || 'N/A';
  const destIp = src.dest_ip || src['destination.ip'] || 'N/A';
  const rule = src['alert.signature'] ||
               (src.alert && src.alert.signature) ||
               src['rule.name'] ||
               src.msg ||
               'Règle inconnue';
  const severity = (src.alert && src.alert.severity) ||
                   src.priority ||
                   src['event.severity_label'] ||
                   src.severity || 'N/A';
  const category = (src.alert && src.alert.category) || src['event.category'] || '';
  const proto = src.proto || src['network.transport'] || 'N/A';
  const destPort = src.dest_port || src['destination.port'] || 'N/A';
  const engine = src.engine || (hit._index || '').split('-')[0] || 'Unknown';
  return { ts, srcIp, destIp, rule, severity, category, proto, destPort, engine };
});

return [{ json: { alerts, count: alerts.length } }];

// Construit le payload Adaptive Card Teams
const { alerts, count } = $input.item.json;
const portalUrl = 'http://localhost:3000';

// Top 5 alertes pour la carte
const top = alerts.slice(0, 5);

const factSets = top.map(a => ({
  type: 'FactSet',
  facts: [
    { title: 'Heure', value: a.ts },
    { title: 'IP source', value: a.srcIp },
    { title: 'IP dest', value: `${a.destIp}:${a.destPort}` },
    { title: 'Règle', value: String(a.rule).substring(0, 80) },
    { title: 'Sévérité', value: String(a.severity) },
    { title: 'Moteur', value: a.engine },
    { title: 'Proto', value: a.proto }
  ]
}));

const payload = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `NetWatch — ${count} alerte(s) HIGH/CRITICAL`,
            weight: 'Bolder',
            size: 'Large',
            color: 'Attention',
            wrap: true
          },
          {
            type: 'TextBlock',
            text: `Dernières 5 minutes — ${new Date().toISOString()}`,
            size: 'Small',
            isSubtle: true
          },
          ...factSets
        ],
        actions: [
          {
            type: 'Action.OpenUrl',
            title: 'Ouvrir le portail NetWatch',
            url: portalUrl
          }
        ]
      }
    }
  ]
};

return [{ json: payload }];
